import stylesText from './quick-log-bar.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { navigate } from '../../../router.js';
import { appTodayString } from '../../../services/app-timezone.service.js';
import { createQuickLogMoreEvent } from '../health-events.js';

const styles = cssStyleSheet(stylesText);

/**
 * Story 258 — the always-on meal-slot log bar (wireframe 3a/3b). A slot tap
 * jumps straight into the food-entry flow for the bar's date (attribute,
 * defaulting to today so an overnight-open dashboard never logs to a stale
 * day); `›` asks the host screen to open its more-actions menu.
 */
const template = document.createElement('template');
template.innerHTML = `
    <div class="qlb">
        <button type="button" data-meal="Breakfast">🥣 Bfast</button>
        <button type="button" data-meal="Lunch">🥪 Lunch</button>
        <button type="button" data-meal="Dinner">🍲 Dinner</button>
        <button type="button" data-meal="Snacks">🍎 Snack</button>
        <button type="button" id="qlb-more" title="More actions">›</button>
    </div>
`;

export class QuickLogBar extends HTMLElement {
    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));

        for (const button of shadow.querySelectorAll<HTMLButtonElement>('button[data-meal]')) {
            button.addEventListener('click', () => {
                const date = this.getAttribute('date') ?? appTodayString();
                navigate(`/health/food-entry/${date}/${button.dataset.meal}`);
            });
        }
        shadow.getElementById('qlb-more')!.addEventListener('click', () => {
            this.dispatchEvent(createQuickLogMoreEvent());
        });
    }
}

if (!customElements.get('quick-log-bar')) {
    customElements.define('quick-log-bar', QuickLogBar);
}
