/**
 * Story 258 — energy burn per activity, with an honest fallback.
 *
 * HC-synced rows carry no energy (the bridge serves none until story 259),
 * so `calories_burned` is null for most real data. The v3 timeline and day
 * detail still need a day-burn figure, so absent a real value we estimate
 * kcal ≈ MET × body-weight-kg × hours (1 MET ≈ 1 kcal/kg/h). Estimates are
 * flagged so the UI can prefix them with `~`; a stored `calories_burned`
 * always wins and renders bare. The estimate needs a body weight, which comes
 * from the nearest recorded weight entry (`weightKgOnDate`); with no weight on
 * record the weight is `null` and estimation is skipped rather than faked
 * against an invented default (story 261) — stored values still render.
 * MET values are Compendium-of-Physical-
 * Activities ballpark figures — avowedly rough, replaced by watch data as
 * story 259 backfills it. Walking/running/cycling use pace-banded MET
 * (below) when distance is known; other types stay flat since "pace"
 * doesn't mean much for e.g. interval or strength work.
 */

import type { ActivityType } from '../types/health.js';

export const ACTIVITY_MET: Record<ActivityType, number> = {
    walking: 3.3,
    hiking: 5.3,
    running: 9.8,
    cycling: 7.5,
    swimming: 6,
    tennis: 7.3,
    ice_skate: 7,
    alpine_ski: 5.3,
    // TRIB3/Barry's-style bootcamp classes (weighted circuits, minimal rest)
    // run hotter than generic calisthenics — published estimates for that
    // class format land around 9-10 MET session-average.
    hiit: 9,
    weight_training: 3.5,
    workout: 5,
};

/**
 * Compendium-of-Physical-Activities speed bands (km/h), one table per type
 * where pace materially changes intensity. Bands are checked in order and
 * `maxKmh` is an exclusive upper bound; the last band is open-ended.
 */
const PACE_BANDED_MET: Partial<Record<ActivityType, ReadonlyArray<{ maxKmh: number; met: number }>>> = {
    walking: [
        { maxKmh: 3.2, met: 2.8 },
        { maxKmh: 4.8, met: 3.3 },
        { maxKmh: 5.6, met: 3.8 },
        { maxKmh: 6.4, met: 5.0 },
        { maxKmh: Infinity, met: 6.3 },
    ],
    running: [
        { maxKmh: 8.0, met: 6.0 },
        { maxKmh: 9.7, met: 8.3 },
        { maxKmh: 11.3, met: 9.8 },
        { maxKmh: 12.9, met: 11.0 },
        { maxKmh: 14.5, met: 11.8 },
        { maxKmh: Infinity, met: 12.8 },
    ],
    cycling: [
        { maxKmh: 16.0, met: 4.0 },
        { maxKmh: 19.3, met: 6.8 },
        { maxKmh: 22.5, met: 8.0 },
        { maxKmh: 25.7, met: 10.0 },
        { maxKmh: 30.6, met: 12.0 },
        { maxKmh: Infinity, met: 15.8 },
    ],
};

/** Falls back to the flat `ACTIVITY_MET` value when distance/duration don't give a usable pace. */
function metFor(type: string, durationHours: number, distanceMeters?: number | null): number {
    const flat = ACTIVITY_MET[type as ActivityType] ?? ACTIVITY_MET.workout;
    const bands = PACE_BANDED_MET[type as ActivityType];
    if (!bands || distanceMeters == null || distanceMeters <= 0 || durationHours <= 0) {
        return flat;
    }
    const speedKmh = distanceMeters / 1000 / durationHours;
    return bands.find((band) => speedKmh < band.maxKmh)?.met ?? flat;
}

export interface ActivityBurnSignal {
    /**
     * `Activity.type` is a plain string (legacy rows predate the story-146
     * closed set — 'gym', 'ice-skating'); unknown values estimate at the
     * generic 'workout' MET.
     */
    type: string;
    duration_minutes?: number | null;
    calories_burned?: number | null;
    /** Same-activity distance, when known — sharpens walking/running/cycling via pace-banded MET. */
    distance_m?: number | null;
}

export interface ActivityBurn {
    kcal: number;
    /** True when the figure is a MET estimate rather than a recorded value. */
    estimated: boolean;
}

export function activityBurnKcal(activity: ActivityBurnSignal, weightKg: number | null): ActivityBurn | null {
    if (activity.calories_burned != null) {
        return { kcal: activity.calories_burned, estimated: false };
    }
    // No recorded weight → no honest MET estimate; a stored value (above) still counts.
    if (weightKg == null) {
        return null;
    }
    if (activity.duration_minutes == null || activity.duration_minutes <= 0) {
        return null;
    }
    const hours = activity.duration_minutes / 60;
    const met = metFor(activity.type, hours, activity.distance_m);
    const kcal = Math.round(met * weightKg * hours);
    return { kcal, estimated: true };
}

/**
 * Day total: basis-less activities contribute nothing; the total is flagged
 * estimated when any contributing part is. An empty day is an exact zero.
 */
export function dayBurnKcal(activities: ActivityBurnSignal[], weightKg: number | null): ActivityBurn {
    let kcal = 0;
    let estimated = false;
    for (const activity of activities) {
        const burn = activityBurnKcal(activity, weightKg);
        if (burn === null) continue;
        kcal += burn.kcal;
        estimated = estimated || burn.estimated;
    }
    return { kcal, estimated };
}

/**
 * The recorded weight closest to `date` (before or after — nearest wins; an
 * exact-distance tie breaks toward the entry on or before the date). Returns
 * `null` when no weight is on record, so callers skip estimation rather than
 * inventing a default body weight (story 261). Reaching forward to a later
 * entry is deliberate: a weigh-in two days after the day is a better basis for
 * that day than one from three weeks earlier.
 */
export function weightKgOnDate(
    entries: ReadonlyArray<{ date: string; weight_kg: number }>,
    date: string,
): number | null {
    if (entries.length === 0) return null;
    const target = Temporal.PlainDate.from(date);
    let best: { weight_kg: number; distance: number; onOrBefore: boolean } | null = null;
    for (const entry of entries) {
        const deltaDays = Temporal.PlainDate.from(entry.date).until(target, { largestUnit: 'day' }).days;
        const distance = Math.abs(deltaDays);
        const onOrBefore = deltaDays >= 0;
        const closer = best === null || distance < best.distance;
        const tieBrokenTowardEarlier = best !== null && distance === best.distance && onOrBefore && !best.onOrBefore;
        if (closer || tieBrokenTowardEarlier) {
            best = { weight_kg: entry.weight_kg, distance, onOrBefore };
        }
    }
    return best!.weight_kg;
}
